--
-- Table structure for table `technicalanalysis`
--

DROP TABLE IF EXISTS `technicalanalysis`;
CREATE TABLE `technicalanalysis` (
  `idtechnicalanalysis` int(11) NOT NULL auto_increment COMMENT 'Index',
  `createddate` datetime NOT NULL default '2009-01-01 00:00:00' COMMENT 'Record Created Date',
  `createduser` int(11) NOT NULL default '0' COMMENT 'Record Created by User',
  `updateddate` timestamp NOT NULL default CURRENT_TIMESTAMP COMMENT 'Record updated date',
  `updateduser` int(11) NOT NULL default '0' COMMENT 'Record Updated by user',
  `symbol` varchar(11) NOT NULL default '' COMMENT 'Stock Symbol',
  `date` date NOT NULL default '0000-00-00' COMMENT 'Date in stockprices',
  `day_close` float NOT NULL default '0' COMMENT 'The daily closing price',
  `typicalprice` float NOT NULL default '0' COMMENT 'The Typical Price is the high plus low plus close divided by 3',
  `movingaverage50` float NOT NULL default '0' COMMENT '50 Day Moving Average',
  `movingaverage200` float NOT NULL default '0' COMMENT '200 Day Moving Average',
  `candlestick` varchar(255) NOT NULL default '' COMMENT 'Candlestick Identified for this date',
  `expmovingaverage9` float NOT NULL COMMENT '9 Day exponential Moving Average',
  `expmovingaverage12` float NOT NULL COMMENT '12 Day exponential Moving Average',
  `expmovingaverage26` float NOT NULL COMMENT '26 Day exponential Moving Average',
  `macd` varchar(255) NOT NULL COMMENT 'Moving Average ConvergenceDivergence describes the rate of changes in EMAs',
  `momentumoscillator` float NOT NULL default '0' COMMENT 'The Longer EMA subtracted from the shorter EMA usually 12 and 26',
  `mamomentum` float NOT NULL default '0' COMMENT 'MACD momentum rising positive is bullish increasing',
  `macrossover` int(1) NOT NULL default '0' COMMENT 'MA crossover True or False',
  `macenterlinecrossover` int(1) NOT NULL default '0' COMMENT 'Is this a centerline crossover of the MA',
  `priceoscillator` float NOT NULL default '0' COMMENT 'Shows the percentage difference between 2 MAs 12 minus 26 div 26',
  `macd_histogram` float NOT NULL default '0' COMMENT 'Difference between MACD and trigger line (ma9)',
  `linearregression` float NOT NULL default '0' COMMENT 'Linear Regression',
  `linearregressionangle` float NOT NULL default '0' COMMENT 'Angle of Linear Regression',
  `linearregressionslope` float NOT NULL default '0' COMMENT 'Slope of Linear Regression',
  `linearregressionintercept` float NOT NULL default '0' COMMENT 'Intercept of Linear Regression',
  `stochastic` float NOT NULL default '0' COMMENT 'Stochastic Indicator',
  `relativestrenghtindex` float NOT NULL default '0' COMMENT 'Relative Strength Index',
  `rsioscillator` float NOT NULL default '0' COMMENT 'Relative Strength Oscillator is a leading indicator',
  `commoditychannelindex` float NOT NULL default '0' COMMENT 'Commodity Channel Index',
  `pricechangepercent` float NOT NULL default '0' COMMENT 'The percentage change of the close price compared to yesterdays close price',
  `volume12` int(11) NOT NULL default '0' COMMENT 'Average Volume for the last 12 days',
  `volume26` int(11) NOT NULL default '0' COMMENT 'Average volume for the last 26 days',
  `volume90` int(11) NOT NULL default '0' COMMENT 'Average volume for the last 90 days',
  `support12` float NOT NULL default '0' COMMENT 'Support level last 12 days',
  `support26` float NOT NULL default '0' COMMENT 'Support level last 26 days',
  `resistance12` float NOT NULL default '0' COMMENT 'Resistance level last 12 days',
  `resistance26` float NOT NULL default '0' COMMENT 'resistance level last 26 days',
  `bollingerbandmiddle` float NOT NULL default '0' COMMENT 'The middle bollinger band',
  `bollingerbandupper` float NOT NULL default '0' COMMENT 'The upper bollinger band',
  `bollingerbandlower` float NOT NULL default '0' COMMENT 'The lower bollinger band',
  `bollingerpercentb` float NOT NULL default '0' COMMENT 'The bollinger percent b indicator',
  `bollingerbandwidth` float NOT NULL default '0' COMMENT 'The bollinger bandwidth addresses the spread of the values',
  `coefficientofvariation` float NOT NULL default '0' COMMENT 'The coefficient of variation is 1/4 of the bandwidth',
  `movingaverage260` float NOT NULL default '0' COMMENT 'Moving Average for 260 days (1 trading year)',
  `standarddeviation260` float NOT NULL default '0' COMMENT 'Standard Deviation 260 One trading year',
  `annualreturn` float NOT NULL default '0' COMMENT 'The price appreciation in the last year',
  `annualrisk` float NOT NULL default '0' COMMENT 'The annual risk standard dev divided by annual return',
  `truerange` float NOT NULL COMMENT ' MAX( High0-Low0, High0-Close1, Close1 - Low0 )',
  `expmovingaverage90` float NOT NULL COMMENT '90 day price EMA ',
  `voltrendind90` varchar(8) NOT NULL COMMENT '90 day Volume trend indicator',
  `voltrendind26` varchar(8) NOT NULL COMMENT '26 day Volume Trend indicator',
  `volume260` float NOT NULL COMMENT 'One year''s volume average',
  `voltrendind260` varchar(8) NOT NULL default '' COMMENT 'Year''s volume trend indicator',
  PRIMARY KEY  (`idtechnicalanalysis`),
  UNIQUE KEY `date_symbol` (`date`,`symbol`,`candlestick`)
) ENGINE=MyISAM AUTO_INCREMENT=192965 DEFAULT CHARSET=latin1;

